    26→export function sanitizeTaxonomy(text: string): string {
    27→  if (!text || typeof text !== 'string') {
    28→    return '';
    29→  }
    30→
    31→  return text
    32→    .toLowerCase()
    33→    .normalize('NFD')
    34→    .replace(/[\u0300-\u036f]/g, '')
    35→    .replace(/[^\w\s]/g, '')
    36→    .replace(/\s+/g, '_')
    37→    .replace(/_+/g, '_')
    38→    .replace(/^_/, '')
    39→    .replace(/_$/, '');
    40→}
